import React from 'react';

const ContactoPage = () => {
  // Imágenes principales y QRs
  const leftImage = {
    src: '/media/contactoPage/UCBA.png',
    alt: 'Entrada UCB',
    link: 'https://www.ucb.edu.bo/',
  };

  const rightColumnImages = [
    {
      main: {
        src: '/media/contactoPage/SIS - H.png',
        alt: 'Logo SIS',
        link: 'https://www.ucb.edu.bo/contacto',
      },
      qr: {
        src: '/media/contactoPage/qr.png',
        alt: 'QR SIS',
        link: 'https://www.ucb.edu.bo/contacto/qr',
      },
    },
    {
      main: {
        src: '/media/contactoPage/IIE - H.png',
        alt: 'Logo ADM',
        link: 'https://www.ucb.edu.bo/nosotros',
      },
      qr: {
        src: '/media/contactoPage/qr.png',
        alt: 'QR ADM',
        link: 'https://www.ucb.edu.bo/nosotros/qr',
      },
    },
  ];

  return (
    <main style={styles.page}>
      <div style={styles.container}>
        <h1 style={styles.title}>UNIVERSIDAD CATÓLICA BOLIVIANA</h1>

        {/* Contenedor fila principal */}
        <div style={styles.mainRow}>

          {/* Imagen grande izquierda */}
          <a
            href={leftImage.link}
            target="_blank"
            rel="noopener noreferrer"
            style={styles.leftImageLink}
          >
            <img src={leftImage.src} alt={leftImage.alt} style={styles.leftImage} />
          </a>

          {/* Columnas derechas */}
          {rightColumnImages.map(({ main, qr }, idx) => (
            <div key={idx} style={styles.rightColumn}>
              {/* Imagen principal arriba */}
              <a
                href={main.link}
                target="_blank"
                rel="noopener noreferrer"
                style={styles.rightImageLink}
              >
                <img src={main.src} alt={main.alt} style={styles.rightImage} />
              </a>
              {/* QR debajo */}
              <a
                href={qr.link}
                target="_blank"
                rel="noopener noreferrer"
                style={styles.rightImageLink}
              >
                <img src={qr.src} alt={qr.alt} style={styles.qrImage} />
              </a>
            </div>
          ))}
        </div>
      </div>
    </main>
  );
};

const styles = {
  page: {
    backgroundColor: '#F8F0E3',
    minHeight: '100vh',
    padding: '3rem 1rem',
    fontFamily: "'Segoe UI', Tahoma, Geneva, Verdana, sans-serif",
  },
  container: {
    maxWidth: 960,
    margin: '0 auto',
    padding: '0 1rem',
    color: '#052018',
  },
  title: {
    fontSize: '3rem',
    fontWeight: '900',
    marginBottom: '2rem',
    textAlign: 'center',
    color: '#052018',
  },

  mainRow: {
    display: 'flex',
    gap: '1.5rem',
    alignItems: 'stretch', // para igualar altura
  },

  leftImageLink: {
    flex: '1 1 60%',
    maxWidth: '60%',
    display: 'block',
  },
  leftImage: {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },

  rightColumn: {
    flex: '1 1 20%',
    display: 'flex',
    flexDirection: 'column',
    justifyContent: 'space-between',
    gap: '1.5rem',
  },

  rightImageLink: {
    display: 'block',
    flex: '1 1 50%', // cada imagen toma mitad del espacio vertical
  },
  rightImage: {
    width: '100%',
    height: '100%',
    objectFit: 'contain',
    borderRadius: 16,
    boxShadow: '0 2px 12px rgba(0,0,0,0.15)',
    display: 'block',
  },

  qrImage: {
    width: '100%',
    height: '100%',
    objectFit: 'contain',
    borderRadius: 12,
    boxShadow: '0 1px 8px rgba(0,0,0,0.1)',
    display: 'block',
  },
};

export default ContactoPage;
